<template>
  <div>
    <h3 class="page-title">系统配置</h3>
    <el-table :data="configs" stripe v-loading="loading">
      <el-table-column prop="configKey" label="配置键" width="200" />
      <el-table-column prop="configValue" label="配置值" />
      <el-table-column prop="description" label="说明" />
      <el-table-column label="操作" width="120">
        <template slot-scope="{row}">
          <el-button size="mini" type="primary" @click="editRow(row)">编辑</el-button>
        </template>
      </el-table-column>
    </el-table>

    <el-dialog title="编辑配置" :visible.sync="showDialog" width="500px">
      <el-form label-width="80px">
        <el-form-item label="键"><el-input :value="editForm.configKey" disabled /></el-form-item>
        <el-form-item label="值"><el-input type="textarea" v-model="editForm.configValue" :rows="3" /></el-form-item>
      </el-form>
      <span slot="footer"><el-button @click="showDialog=false">取消</el-button><el-button type="primary" @click="handleSave">保存</el-button></span>
    </el-dialog>
  </div>
</template>

<script>
import { adminApi } from '../../api';
export default {
  name: 'AdminConfig',
  data() { return { configs: [], loading: true, showDialog: false, editForm: {} }; },
  created() { this.load(); },
  methods: {
    async load() {
      this.loading = true;
      const res = await adminApi.getConfig();
      if (res.code === 200) this.configs = res.data || [];
      this.loading = false;
    },
    editRow(row) { this.editForm = { ...row }; this.showDialog = true; },
    async handleSave() {
      await adminApi.updateConfig(this.editForm);
      this.$message.success('保存成功');
      this.showDialog = false;
      this.load();
    }
  }
};
</script>
